class Solution:
    def mergeAdjacent(self, nums: List[int]) -> List[int]:
        # Literal simulation of the spec: repeatedly scan from the very start
        # for the leftmost adjacent equal pair, merge just that pair, then
        # rescan from scratch. Independent of (and much slower than) the
        # stack-based optimal solution -- used only as a differential check.
        arr = list(nums)
        while True:
            merge_at = -1
            for i in range(len(arr) - 1):
                if arr[i] == arr[i + 1]:
                    merge_at = i
                    break
            if merge_at == -1:
                return arr
            arr[merge_at:merge_at + 2] = [arr[merge_at] + arr[merge_at + 1]]

