class Solution:
    def mergeAdjacent(self, nums: List[int]) -> List[int]:
        stack: List[int] = []
        for num in nums:
            cur = num
            while stack and stack[-1] == cur:
                cur += stack.pop()
            stack.append(cur)
        return stack

