var mergeAdjacent = function(nums) {
    const stack = [];
    for (const num of nums) {
        let cur = num;
        while (stack.length && stack[stack.length - 1] === cur) {
            cur += stack.pop();
        }
        stack.push(cur);
    }
    return stack;
};
